package com.banking.service;

import com.banking.model.BankingTransaction;
import com.banking.model.TransactionRequest;
import com.banking.model.TransactionResponse;

import javax.jws.WebService;
import java.math.BigDecimal;
import java.util.Date;
import java.util.HashMap;
import java.util.Map;
import java.util.UUID;
import java.util.logging.Logger;

@WebService(
    serviceName = "BankingService",
    portName = "BankingServicePort",
    targetNamespace = "http://banking.com/service",
    endpointInterface = "com.banking.service.BankingService"
)
public class BankingServiceImpl implements BankingService {

    private static final Logger logger = Logger.getLogger(BankingServiceImpl.class.getName());
    private static final Map<String, BankingTransaction> transactionStore = new HashMap<>();
    private static final Map<String, BigDecimal> accountBalances = new HashMap<>();

    static {
        accountBalances.put("ACC001", new BigDecimal("10000.00"));
        accountBalances.put("ACC002", new BigDecimal("5000.00"));
        accountBalances.put("ACC003", new BigDecimal("15000.00"));
    }

    @Override
    public TransactionResponse processTransaction(TransactionRequest request) {
        logger.info("Processing transaction from " + request.getFromAccount() + 
                   " to " + request.getToAccount());

        try {
            if (request.getFromAccount() == null || request.getToAccount() == null) {
                return new TransactionResponse(false, null, 
                    "Invalid account numbers", null);
            }

            if (request.getAmount() == null || request.getAmount().compareTo(BigDecimal.ZERO) <= 0) {
                return new TransactionResponse(false, null, 
                    "Invalid transaction amount", null);
            }

            BigDecimal fromBalance = accountBalances.getOrDefault(
                request.getFromAccount(), BigDecimal.ZERO);

            if (fromBalance.compareTo(request.getAmount()) < 0) {
                return new TransactionResponse(false, null, 
                    "Insufficient funds", null);
            }

            String transactionId = UUID.randomUUID().toString();
            BankingTransaction transaction = new BankingTransaction(
                transactionId,
                request.getFromAccount(),
                request.getToAccount(),
                request.getAmount(),
                request.getCurrency(),
                new Date(),
                "COMPLETED",
                request.getDescription()
            );

            accountBalances.put(request.getFromAccount(), 
                fromBalance.subtract(request.getAmount()));
            
            BigDecimal toBalance = accountBalances.getOrDefault(
                request.getToAccount(), BigDecimal.ZERO);
            accountBalances.put(request.getToAccount(), 
                toBalance.add(request.getAmount()));

            transactionStore.put(transactionId, transaction);

            logger.info("Transaction completed successfully: " + transactionId);

            return new TransactionResponse(true, transactionId, 
                "Transaction completed successfully", transaction);

        } catch (Exception e) {
            logger.severe("Error processing transaction: " + e.getMessage());
            return new TransactionResponse(false, null, 
                "Transaction failed: " + e.getMessage(), null);
        }
    }

    @Override
    public TransactionResponse getTransactionStatus(String transactionId) {
        logger.info("Getting transaction status for: " + transactionId);

        BankingTransaction transaction = transactionStore.get(transactionId);
        if (transaction != null) {
            return new TransactionResponse(true, transactionId, 
                "Transaction found", transaction);
        } else {
            return new TransactionResponse(false, transactionId, 
                "Transaction not found", null);
        }
    }

    @Override
    public String getAccountBalance(String accountNumber) {
        logger.info("Getting balance for account: " + accountNumber);

        BigDecimal balance = accountBalances.get(accountNumber);
        if (balance != null) {
            return "Account " + accountNumber + " balance: " + balance.toString();
        } else {
            return "Account not found";
        }
    }
}

