package com.banking.security;

import org.apache.cxf.binding.soap.SoapMessage;
import org.apache.cxf.interceptor.Fault;
import org.apache.cxf.phase.AbstractPhaseInterceptor;
import org.apache.cxf.phase.Phase;
import org.apache.wss4j.common.ext.WSSecurityException;
import org.apache.wss4j.dom.WSConstants;
import org.apache.wss4j.dom.engine.WSSConfig;
import org.apache.wss4j.dom.engine.WSSecurityEngine;
import org.apache.wss4j.dom.handler.RequestData;
import org.apache.wss4j.dom.handler.WSHandlerResult;
import org.w3c.dom.Document;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.ByteArrayInputStream;
import java.util.List;
import java.util.logging.Logger;

public class SignatureVerificationInterceptor extends AbstractPhaseInterceptor<SoapMessage> {

    private static final Logger logger = Logger.getLogger(SignatureVerificationInterceptor.class.getName());

    public SignatureVerificationInterceptor() {
        super(Phase.PRE_PROTOCOL);
    }

    @Override
    public void handleMessage(SoapMessage message) throws Fault {
        logger.info("Verifying XML signature in SOAP message");

        try {
            Document doc = message.getContent(Document.class);
            
            if (doc == null) {
                logger.warning("No document found in message");
                return;
            }

            WSSecurityEngine secEngine = new WSSecurityEngine();
            WSSConfig.init();

            RequestData reqData = new RequestData();
            reqData.setSigVerCrypto(CryptoFactory.getCrypto());
            reqData.setCallbackHandler(new KeystoreCallbackHandler());

            List<WSHandlerResult> results = secEngine.processSecurityHeader(doc, reqData);

            if (results != null && !results.isEmpty()) {
                logger.info("Signature verification successful");
                message.put("signature.verified", true);
            } else {
                logger.warning("No security results found");
                message.put("signature.verified", false);
            }

        } catch (WSSecurityException e) {
            logger.severe("Signature verification failed: " + e.getMessage());
            throw new Fault(new Exception("Invalid signature: " + e.getMessage()));
        } catch (Exception e) {
            logger.severe("Error during signature verification: " + e.getMessage());
            throw new Fault(e);
        }
    }
}

