package com.banking.security;

import org.apache.wss4j.common.crypto.Crypto;
import org.apache.wss4j.common.crypto.CryptoFactory;
import org.apache.wss4j.common.ext.WSSecurityException;

import java.util.Properties;
import java.util.logging.Logger;

public class CryptoFactory {

    private static final Logger logger = Logger.getLogger(CryptoFactory.class.getName());
    private static Crypto crypto;

    public static synchronized Crypto getCrypto() throws WSSecurityException {
        if (crypto == null) {
            Properties properties = new Properties();
            properties.setProperty("org.apache.wss4j.crypto.provider", 
                "org.apache.wss4j.common.crypto.Merlin");
            properties.setProperty("org.apache.wss4j.crypto.merlin.keystore.type", "JKS");
            properties.setProperty("org.apache.wss4j.crypto.merlin.keystore.file", 
                "banking-keystore.jks");
            properties.setProperty("org.apache.wss4j.crypto.merlin.keystore.password", 
                "changeit");
            properties.setProperty("org.apache.wss4j.crypto.merlin.keystore.alias", 
                "banking");

            crypto = org.apache.wss4j.common.crypto.CryptoFactory.getInstance(properties);
            logger.info("Crypto instance created successfully");
        }
        return crypto;
    }
}

