package com.banking.security;

import org.apache.wss4j.common.ext.WSPasswordCallback;

import javax.security.auth.callback.Callback;
import javax.security.auth.callback.CallbackHandler;
import javax.security.auth.callback.UnsupportedCallbackException;
import java.io.IOException;
import java.util.HashMap;
import java.util.Map;
import java.util.logging.Logger;

public class KeystoreCallbackHandler implements CallbackHandler {

    private static final Logger logger = Logger.getLogger(KeystoreCallbackHandler.class.getName());
    private static final Map<String, String> passwords = new HashMap<>();

    static {
        passwords.put("banking", "changeit");
        passwords.put("client", "changeit");
    }

    @Override
    public void handle(Callback[] callbacks) throws IOException, UnsupportedCallbackException {
        for (Callback callback : callbacks) {
            if (callback instanceof WSPasswordCallback) {
                WSPasswordCallback pc = (WSPasswordCallback) callback;
                String id = pc.getIdentifier();
                
                logger.info("Password callback for identifier: " + id);
                
                String password = passwords.get(id);
                if (password != null) {
                    pc.setPassword(password);
                } else {
                    logger.warning("No password found for identifier: " + id);
                }
            } else {
                throw new UnsupportedCallbackException(callback, "Unrecognized Callback");
            }
        }
    }
}

